1	/**
2	 * li-client.ts — LayerInfinite REST API client for the benchmark.
3	 * Uses the REST API directly (not MCP) for programmatic control.
4	 * Includes rate-limit-aware delays between requests.
5	 */
6	
7	const LI_BASE_URL = 'https://layerinfinite.me';
8	const LI_API_KEY = 'layerinfinite_60a7e2729d358205f2f2433e4e4cf78d';
9	
10	/** Delay to respect the 300 req/min rate limit. */
11	const REQUEST_DELAY_MS = 250; // 4 req/sec = 240 req/min — safe under 300 limit
12	
13	async function delay(ms: number): Promise<void> {
14	  return new Promise(resolve => setTimeout(resolve, ms));
15	}
16	
17	interface LIRequestOptions {
18	  method: 'GET' | 'POST' | 'PUT';
19	  path: string;
20	  body?: Record<string, unknown>;
21	  params?: Record<string, string>;
22	}
23	
24	async function liRequest<T>(opts: LIRequestOptions): Promise<{ ok: boolean; status: number; data: T | null; error?: string }> {
25	  const url = new URL(`${LI_BASE_URL}${opts.path}`);
26	  if (opts.params) {
27	    for (const [k, v] of Object.entries(opts.params)) {
28	      url.searchParams.set(k, v);
29	    }
30	  }
31	
32	  const fetchOpts: RequestInit = {
33	    method: opts.method,
34	    headers: {
35	      'X-API-Key': LI_API_KEY,
36	      'Content-Type': 'application/json',
37	    },
38	  };
39	
40	  if (opts.body) {
41	    fetchOpts.body = JSON.stringify(opts.body);
42	  }
43	
44	  // Rate limit safety — wait between requests
45	  await delay(REQUEST_DELAY_MS);
46	
47	  try {
48	    const res = await fetch(url.toString(), fetchOpts);
49	    const data = await res.json() as T;
50	
51	    if (res.status === 429) {
52	      // Rate limited — wait and retry once
53	      const retryAfter = parseInt(res.headers.get('Retry-After') ?? '5', 10);
54	      console.log(`  ⚠️  Rate limited. Waiting ${retryAfter}s...`);
55	      await delay(retryAfter * 1000);
56	      const retryRes = await fetch(url.toString(), fetchOpts);
57	      const retryData = await retryRes.json() as T;
58	      return { ok: retryRes.ok, status: retryRes.status, data: retryData };
59	    }
60	
61	    return { ok: res.ok, status: res.status, data };
62	  } catch (err: any) {
63	    return { ok: false, status: 0, data: null, error: err.message };
64	  }
65	}
