67	/** Log an outcome to LayerInfinite. */
68	export async function logOutcome(params: {
69	  action_name: string;
70	  issue_type: string;
71	  success: boolean;
72	  outcome_score?: number;
73	  response_ms?: number;
74	  metadata?: Record<string, unknown>;
75	}): Promise<boolean> {
76	  const result = await liRequest<any>({
77	    method: 'POST',
78	    path: '/v1/log-outcome',
79	    body: {
80	      action_name: params.action_name,
81	      issue_type: params.issue_type,
82	      success: params.success,
83	      outcome_score: params.outcome_score ?? (params.success ? 1.0 : 0.0),
84	      response_ms: params.response_ms ?? 0,
85	      metadata: params.metadata ?? {},
86	    },
87	  });
88	
89	  if (!result.ok) {
90	    console.error(`  ❌ log-outcome failed (${result.status}):`, result.error ?? result.data);
91	  }
92	  return result.ok;
93	}
