95	/** Get scored actions from LayerInfinite for a given task. */
96	export async function getScores(issueType: string): Promise<{
97	  actions: Array<{ action_name: string; score: number; total_runs: number; success_rate: number }>;
98	  recommendation?: { action: string; confidence: string };
99	} | null> {
100	  const result = await liRequest<any>({
101	    method: 'GET',
102	    path: '/v1/get-scores',
103	    params: { issue_type: issueType },
104	  });
105	
106	  if (!result.ok || !result.data) return null;
107	
108	  const data = result.data;
109	  const rankedActions = data.ranked_actions ?? data.scores ?? data.actions ?? [];
110	  return {
111	    actions: rankedActions.map((a: any) => ({
112	      action_name: a.action_name,
113	      score: a.composite_score ?? a.score ?? a.weighted_score ?? 0,
114	      total_runs: a.total_attempts ?? a.total_runs ?? a.total_outcomes ?? 0,
115	      success_rate: a.composite_score ?? a.success_rate ?? 0,
116	    })),
117	    recommendation: data.top_action
118	      ? { action: data.top_action.action_name, confidence: data.cold_start ? 'cold_start' : 'empirical' }
119	      : data.recommendation ?? data.policy_recommendation ?? undefined,
120	  };
121	}
